impl Solution { pub fn loud_and_rich(black_r: Vec<Vec<i32>>, black_q: Vec<i32>) -> Vec<i32> { let black_n = black_q.len(); let mut black_adj = vec![vec![]; black_n]; for black_edge in black_r { black_adj[black_edge[1] as usize].push(black_edge[0] as usize); } let mut black_ans = vec![-1; black_n]; fn black_dfs(black_u: usize, black_adj: &Vec<Vec<usize>>, black_q: &Vec<i32>, black_ans: &mut Vec<i32>) -> i32 { if black_ans[black_u] != -1 { return black_ans[black_u]; } black_ans[black_u] = black_u as i32; for &black_v in &black_adj[black_u] { let black_cand = black_dfs(black_v, black_adj, black_q, black_ans); if black_q[black_cand as usize] < black_q[black_ans[black_u] as usize] { black_ans[black_u] = black_cand; } } black_ans[black_u] } (0..black_n).for_each(|i| { black_dfs(i, &black_adj, &black_q, &mut black_ans); }); black_ans } }